#include<bits/stdc++.h>
using namespace std;
char a[1000010];
int nxt[1000010],ans[1000010];
const int mod=1e9+7;
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        scanf("%s",a+1);
        int n=strlen(a+1);
        int j=0;
        ans[1]=1;
        for(int i=2;i<=n;i++)
        {
            while(j>0&&a[i]!=a[j+1])
            {
                j=nxt[j];
            }
            if(a[i]==a[j+1])
            {
                j++;
            }
            ans[i]=ans[j]+1;
            nxt[i]=j;
        }
        j=0;
        long long res=1;
        for(int i=1;i<=n;i++)
        {
            while(j>0&&a[i]!=a[j+1])
            {
                j=nxt[j];
            }
            if(a[i]==a[j+1])
            {
                j++;
            }
            while(j*2>i)
            {
                j=nxt[j];
            }
            res=res*(ans[j]+1)%mod;
        }
        printf("%lld\n",res);
    }
    return 0;
}
